#include<bits/stdc++.h>
using namespace std;

  

class TS{

    private:

        int n;

        vector<int> time_;

        vector<vector<int>> prereqs;

        vector<int> state;

        vector<int> order;

        bool hasCycle;

  

        void dfs(int node){

            state[node] = 1;

  

            for(int pre : prereqs[node]){

                if(state[pre] == 0){

                    dfs(pre);

                    if(hasCycle){

                        return ;

                    }

                }

                else if(state[pre] == 1){

                    hasCycle = 1;

                    return;

                }

            }

            state[node] = 2;

            order.push_back(node);

        }

    public:

        TS(int n, vector<int>& taskTimes, vector<vector<int>>& deps) : n(n), time_(taskTimes), prereqs(n), state(n,0), hasCycle(false){

            for(auto& edge : deps){

                int u = edge[0];

                int v = edge[1];

                prereqs[v].push_back(u);

            }

        }

  

        void solve(){

            for(int i =0; i < n; i++){

                if(state[i] == 0){

                    dfs(i);

                    if(hasCycle){

                        cout << "cycle" << "\n";

                        return;

                    }

                }

            }

            for (int node : order) cout << node << " ";

            cout << "\n";

        }

};

  

int main(){

    int n = 4;

    vector<int> taskTimes = {3,2,4,5};

  

    vector<vector<int>> deps = {{0,2},{1,2},{2,3}};

  

    TS ts1(n, taskTimes, deps);

    ts1.solve();

}

## Notes

- prereqs[v] stores prerequisites of v

- 3 states: 0=unvisited, 1=visiting, 2=done

- state[pre]==1 → back edge → cycle

- state[pre]==2 → cross edge → skip
  
